470	    res.writeHead(403);
471	    res.end("Forbidden");
472	    return;
473	  }
474	
475	  fs.readFile(filePath, function (err, data) {
476	    if (err) {
477	      res.writeHead(404);
478	      res.end("Not found: " + reqPath);
479	      return;
480	    }
481	    var ext = path.extname(filePath).toLowerCase();
482	    // Force fresh JS / HTML / CSS during active development. Without this
483	    // browsers cache app.js hard, so newly-edited features (e.g. emphasis
484	    // overlay) silently keep using the old code on reload.
485	    var headers = { "Content-Type": MIME[ext] || "application/octet-stream" };
486	    if (ext === ".js" || ext === ".html" || ext === ".css") {
487	      headers["Cache-Control"] = "no-store, no-cache, must-revalidate";
488	      headers["Pragma"] = "no-cache";
489	      headers["Expires"] = "0";
490	    }
491	    // #SEC1/C: Frame-busting headers (Content-Security-Policy +
492	    // X-Frame-Options) are set globally by cors() via setHeader, so they
493	    // ride along on this writeHead without being duplicated here.
494	    res.writeHead(200, headers);
495	    res.end(data);
496	  });
497	}
498	
499	// ── Router ──
500	
501	var server = http.createServer(function (req, res) {
502	  cors(req, res);
503	
504	  // Handle CORS preflight
505	  if (req.method === "OPTIONS") {
506	    res.writeHead(204);
507	    res.end();
508	    return;
509	  }
510	
