512	  var isApi = pathname.indexOf("/api/") === 0;
513	
514	  // For API endpoints, reject requests whose Origin (when present) is not
515	  // one of our loopback origins. Static asset requests (no /api/ prefix)
516	  // can come from anywhere — they're just files in ROOT.
517	  if (isApi && !isOriginAllowed(req)) {
518	    jsonReply(res, 403, { error: "Cross-origin API requests are not allowed" });
519	    return;
520	  }
521	
522	  if (pathname === "/api/ping") return handlePing(req, res);
523	  if (pathname === "/api/write-file" && req.method === "POST") return handleWriteFile(req, res);
524	  if (pathname === "/api/open-file"  && req.method === "POST") return handleOpenFile(req, res);
