168	    // Traditional → Simplified (zh-TW → zh-CN). Google Translate
169	    // handles the cross-script conversion when language hints are
170	    // explicit on both ends; using "auto" for either side would let
171	    // Google fall back to the document's overall language guess and
172	    // skip the script transform on shorter strings.
173	    if (direction === "tw-cn" || direction === "tc-sc") {
174	      next.sourceLang = "zh-TW";
175	      next.targetLang = "zh-CN";
