229	  function getProviderAdapter(providerKey) {
230	    if (providerKey === PROVIDER_GOOGLE_WEB) {
231	      return {
232	        prepareConfig: async (cfg) => cfg,
233	        translateBatch: async (texts, cfg) => await translateBatchViaGoogleWeb(texts, cfg)
234	      };
