467	  async function runAutoTranslate(opts) {
468	    const automation = opts || {};
469	    const silent = !!automation.silent;
470	    const bridge = getBridge();
471	    const btn = document.getElementById("autoTranslateBtn");
472	    const label = document.getElementById("translateBtnLabel");
473	    const originalLabel = label ? label.textContent : "";
474	    let provider;
475	    let cfg;
476	    let rows;
477	    let candidates;
478	    let statusBefore;
479	    let totalUpdated = 0;
480	    let totalSkipped = 0;
481	    let totalFailed = 0;
482	    let i;
483	    let batch;
484	    let translatedBatch;
485	    let payload;
486	    let applyStats;
487	    let doneCount;
488	    let maskedList;
489	
490	    if (!bridge) {
491	      if (!silent) alert("Dev bridge not ready. Refresh page and retry.");
492	      return { ok: false, reason: "no_bridge" };
493	    }
494	    if (!bridge.isPackageLoaded()) {
495	      if (!silent) alert("Load a translation package first.");
496	      return { ok: false, reason: "no_package" };
497	    }
498	    if (running) {
499	      return { ok: false, reason: "already_running" };
500	    }
501	
502	    try {
503	      provider = await prepareProviderContext(loadConfig());
504	    } catch (err) {
505	      if (!silent) alert(safeStr(err && err.message) || "Provider configuration is invalid.");
506	      return { ok: false, reason: "provider_config", error: safeStr(err && err.message) };
507	    }
508	    cfg = provider.cfg;
509	    if (automation.overwriteExisting !== undefined) {
510	      cfg.overwriteExisting = !!automation.overwriteExisting;
511	    }
512	    saveConfig(cfg);
513	
514	    rows = Array.isArray(bridge.getRows()) ? bridge.getRows() : [];
515	    candidates = filterCandidates(rows, cfg);
516	    if (candidates.length === 0) {
517	      if (!silent) alert("No eligible segments to auto-translate under current config.");
518	      return { ok: true, candidates: 0, updated: 0, skipped: 0, failed: 0 };
519	    }
520	
521	    if (!silent) {
522	      const directionLabel = buildDirectionSummaryText(cfg);
523	      if (!window.confirm(
524	        "Auto-translate " + String(candidates.length) + " segments?\n" +
525	        "Direction: " + directionLabel + "\n" +
526	        "Provider: " + cfg.provider
527	      )) {
528	        return { ok: false, reason: "user_cancelled" };
529	      }
530	    }
531	
532	    running = true;
533	    statusBefore = safeStr(bridge.getStatusText());
534	    if (btn) {
535	      btn.disabled = true;
536	    }
537	    if (label) {
538	      label.textContent = "Translating...";
539	    }
540	
541	    try {
542	      for (i = 0; i < candidates.length; i += cfg.batchSize) {
543	        batch = candidates.slice(i, i + cfg.batchSize);
544	        doneCount = Math.min(i + batch.length, candidates.length);
545	        bridge.setStatusText(
546	          "[AUTO] Translating " + String(doneCount) + "/" + String(candidates.length) + " ..."
547	        );
548	
549	        maskedList = batch.map(row => maskControlTokens(row.source_text));
550	        translatedBatch = await provider.adapter.translateBatch(
551	          maskedList.map(it => it.masked),
552	          cfg
553	        );
554	        payload = batchToPayload(batch, maskedList, translatedBatch);
555	
556	        applyStats = bridge.applyRows(payload, {
557	          overwriteExisting: cfg.overwriteExisting,
558	          status: "translated",
559	          render: false
560	        });
561	        totalUpdated += Number(applyStats && applyStats.updated) || 0;
562	        totalSkipped +=
563	          (Number(applyStats && applyStats.skipped_existing) || 0) +
564	          (Number(applyStats && applyStats.skipped_locked) || 0) +
565	          (Number(applyStats && applyStats.skipped_missing) || 0) +
566	          (Number(applyStats && applyStats.skipped_empty) || 0);
567	        totalFailed += Math.max(0, batch.length - payload.length);
568	
569	        if (cfg.requestDelayMs > 0 && (i + cfg.batchSize) < candidates.length) {
570	          await sleep(cfg.requestDelayMs);
571	        }
572	      }
573	
574	      bridge.refresh();
575	      bridge.setStatusText(
576	        "[AUTO] Translation complete: " + String(totalUpdated) + " updated, " +
577	        String(totalSkipped) + " skipped, " + String(totalFailed) + " failed"
578	      );
579	      if (!silent) {
580	        alert(
581	          "Auto-translation finished!\n\n" +
582	          "✓ Updated: " + String(totalUpdated) + "\n" +
583	          "○ Skipped: " + String(totalSkipped) + "\n" +
584	          "✗ Failed: " + String(totalFailed)
585	        );
586	      }
587	      if (statusBefore) {
588	        window.setTimeout(() => {
589	          const curBridge = getBridge();
590	          if (curBridge) {
591	            curBridge.setStatusText(statusBefore);
592	          }
593	        }, 4500);
594	      }
595	    } catch (err) {
596	      console.error(err);
597	      bridge.setStatusText("[AUTO] Translation failed: " + safeStr(err && err.message));
598	      if (!silent) {
599	        alert(
600	          "Auto-translation failed:\n\n" +
601	          safeStr(err && err.message) +
602	          "\n\nTip: Click Advanced Settings to configure provider."
603	        );
604	      }
605	      return { ok: false, reason: "translation_error", error: safeStr(err && err.message) };
606	    } finally {
607	      running = false;
608	      if (btn) {
609	        btn.disabled = false;
610	      }
611	      if (label) {
612	        label.textContent = originalLabel || "Auto Translate";
613	      }
614	    }
615	    return { ok: true, candidates: candidates.length, updated: totalUpdated, skipped: totalSkipped, failed: totalFailed };
616	  }
617	
618	  // Public API for automation: lets app.js / Playwright drive a silent run
619	  // with a chosen direction (zh-en / en-zh) without confirm/alert dialogs.
620	  window.__devTranslateRun = async function (opts) {
621	    const o = opts || {};
622	    const direction = o.direction || "";
623	    // Delegate validation to applyQuickDirection so every direction code
624	    // it supports (zh-en, en-zh, tw-cn, tc-sc, cn-tw, sc-tc) flows through
625	    // the automation bridge. Previously this branch hard-coded the
626	    // English ↔ zh-CN pair, silently swallowing any TC/SC direction
627	    // and letting the run inherit whatever config the operator left
628	    // behind — usually the default en → zh-CN, which mistranslates
629	    // when the source is actually Traditional Chinese.
630	    if (direction) {
631	      const cfgNext = applyQuickDirection(loadConfig(), direction);
632	      if (cfgNext) {
633	        saveConfig(cfgNext);
634	        updateButtonLabelFromConfig(cfgNext);
635	      }
636	    }
637	    return await runAutoTranslate({
638	      silent: o.silent !== false,
639	      overwriteExisting: o.overwriteExisting
640	    });
641	  };
642	
643	  function batchToPayload(batch, maskedList, translatedBatch) {
644	    const out = [];
645	    let i;
646	    let translated;
647	    let restored;
648	    for (i = 0; i < batch.length; i += 1) {
649	      translated = safeStr(translatedBatch[i]);
650	      restored = restoreControlTokens(translated, maskedList[i].tokens);
651	      if (!hasEffectiveText(restored)) {
652	        continue;
653	      }
654	      out.push({
655	        tid: batch[i].tid,
656	        target_text: restored
657	      });
658	    }
659	    return out;
660	  }
661	
662	  function filterCandidates(rows, cfg) {
663	    const out = [];
664	    let i;
665	    let row;
666	    let source;
667	    for (i = 0; i < rows.length; i += 1) {
668	      row = rows[i];
669	      if (!row || !row.tid) {
670	        continue;
671	      }
672	      if (row.locked || row.translatable === false) {
673	        continue;
674	      }
675	      source = safeStr(row.source_text);
676	      if (!hasEffectiveText(source)) {
677	        continue;
678	      }
679	      if (!cfg.overwriteExisting && hasEffectiveTranslation(row.target_text)) {
680	        continue;
681	      }
682	      if (cfg.skipReviewed && safeStr(row.display_status) === "reviewed") {
683	        continue;
684	      }
685	      if (cfg.skipSimpleText && !!row.is_simple_text) {
686	        continue;
687	      }
688	      out.push(row);
689	    }
690	    return out;
691	  }
692	
693	  function hasEffectiveText(text) {
694	    return safeStr(text).trim().length > 0;
695	  }
696	
697	  function hasEffectiveTranslation(text) {
698	    return safeStr(text).replace(CONTROL_TOKEN_RE, "").trim().length > 0;
699	  }
700	
701	  function maskControlTokens(text) {
702	    const tokens = [];
703	    const masked = safeStr(text).replace(CONTROL_TOKEN_RE, m => {
704	      const idx = tokens.length;
705	      tokens.push(m);
706	      return "[[__TOK_" + String(idx) + "__]]";
707	    });
708	    return { masked: masked, tokens: tokens };
709	  }
710	
711	  function restoreControlTokens(text, tokens) {
712	    const list = Array.isArray(tokens) ? tokens : [];
713	    return safeStr(text).replace(/\[\[__TOK_(\d+)__\]\]/g, (m, i) => {
714	      const idx = Number(i);
715	      return Number.isFinite(idx) && list[idx] ? list[idx] : m;
716	    });
717	  }
718	
719	  async function translateBatchViaGoogle(texts, cfg) {
720	    const endpoint = safeStr(cfg.googleEndpoint || DEFAULT_CONFIG.googleEndpoint).trim();
721	    const apiKey = safeStr(cfg.apiKey).trim();
722	    const sourceLang = safeStr(cfg.sourceLang).trim();
723	    const targetLang = safeStr(cfg.targetLang).trim();
724	    const payload = {
725	      q: texts,
726	      target: targetLang,
727	      format: "text"
728	    };
729	    let url;
730	    let data;
731	    let list;
732	
733	    if (!apiKey) {
734	      throw new Error("Google API key is empty.");
735	    }
736	    if (!endpoint) {
737	      throw new Error("Google endpoint is empty.");
738	    }
739	    if (!targetLang) {
740	      throw new Error("Target language is empty.");
741	    }
742	    if (sourceLang && sourceLang.toLowerCase() !== "auto") {
743	      payload.source = sourceLang;
744	    }
745	
746	    url = endpoint + "?key=" + encodeURIComponent(apiKey);
747	    data = await postJson(url, payload, "Google translate");
748	    list = extractTranslationList(data);
749	    if (!list) {
750	      throw new Error("Google translate response missing translations array.");
751	    }
752	
753	    return texts.map((_, i) => decodeHtmlEntities(safeStr(list[i] && list[i].translatedText)));
754	  }
755	
756	  async function translateBatchViaGoogleWeb(texts, cfg) {
757	    var rawEndpoint = safeStr(cfg.googleWebEndpoint || DEFAULT_CONFIG.googleWebEndpoint).trim();
758	    // When local server is available, route through its CORS proxy
759	    var endpoint = rawEndpoint;
760	    if (typeof localServer !== "undefined" && localServer.available && rawEndpoint === DEFAULT_CONFIG.googleWebEndpoint) {
761	      endpoint = localServer.baseUrl + "/api/proxy-translate";
762	    }
763	    const sourceLang = safeStr(cfg.sourceLang || "auto").trim() || "auto";
764	    const targetLang = safeStr(cfg.targetLang).trim();
765	
766	    if (!endpoint) {
767	      throw new Error("Google web endpoint is empty.");
768	    }
769	    if (!targetLang) {
770	      throw new Error("Target language is empty.");
771	    }
772	    return await mapWithConcurrency(texts, GOOGLE_WEB_CONCURRENCY, async (text) => {
773	      return await translateOneViaGoogleWeb(
774	        safeStr(text),
775	        sourceLang,
776	        targetLang,
777	        endpoint
778	      );
779	    });
780	  }
781	
782	  async function translateOneViaGoogleWeb(text, sourceLang, targetLang, endpoint) {
783	    const url = endpoint +
784	      "?client=gtx" +
785	      "&sl=" + encodeURIComponent(sourceLang || "auto") +
786	      "&tl=" + encodeURIComponent(targetLang) +
787	      "&dt=t&dt=bd&dj=1&q=" + encodeURIComponent(text);
788	    let resp;
789	    let data;
790	    let errText;
791	    let sentences;
792	
793	    resp = await fetch(url).catch(() => ({ ok: false, status: 0, statusText: "" }));
794	    if (!resp || !resp.ok) {
795	      if (resp && typeof resp.text === "function") {
796	        errText = await safeReadResponseText(resp);
797	      } else {
798	        errText = "";
799	      }
800	      throw new Error(
801	        "Google web translate HTTP " + String(resp && resp.status ? resp.status : 0) +
802	        (errText ? " | " + errText.slice(0, 240) : "")
803	      );
804	    }
805	
806	    data = await resp.json();
807	    sentences = Array.isArray(data && data.sentences) ? data.sentences : [];
808	    if (sentences.length > 0) {
809	      return sentences.map(s => safeStr(s && s.trans)).join("");
810	    }
811	    return "";
812	  }
813	
814	  async function translateBatchViaProxy(texts, cfg) {
815	    const url = safeStr(cfg.proxyUrl).trim();
816	    const sourceLang = safeStr(cfg.sourceLang).trim();
817	    const targetLang = safeStr(cfg.targetLang).trim();
818	    let data;
819	    let list;
820	
821	    if (!url) {
822	      throw new Error("Proxy URL is empty.");
823	    }
824	
825	    data = await postJson(url, {
826	      q: texts,
827	      source: sourceLang,
828	      target: targetLang,
829	      format: "text"
830	    }, "Proxy translate");
831	    list = extractTranslationList(data);
832	    if (Array.isArray(data && data.translations)) {
833	      return texts.map((_, i) => decodeHtmlEntities(safeStr(list[i])));
834	    }
835	    if (Array.isArray(list)) {
836	      return texts.map((_, i) => decodeHtmlEntities(safeStr(list[i] && list[i].translatedText)));
837	    }
838	    throw new Error("Proxy translate response format unsupported.");
839	  }
840	
841	  function translateBatchViaMock(texts, cfg) {
842	    return texts.map(t => "[MOCK-" + cfg.targetLang + "] " + safeStr(t));
843	  }
844	
845	  async function postJson(url, payload, errorLabel) {
846	    let resp;
847	    let errText;
848	
849	    resp = await fetch(url, {
850	      method: "POST",
851	      headers: { "Content-Type": "application/json" },
852	      body: JSON.stringify(payload)
853	    });
854	    if (!resp.ok) {
855	      errText = await safeReadResponseText(resp);
856	      throw new Error(
857	        safeStr(errorLabel) + " HTTP " + String(resp.status) +
858	        (errText ? " | " + errText.slice(0, 240) : "")
859	      );
860	    }
861	    return await resp.json();
862	  }
863	
864	  function extractTranslationList(data) {
865	    if (Array.isArray(data && data.translations)) {
866	      return data.translations;
867	    }
868	    if (data && data.data && Array.isArray(data.data.translations)) {
869	      return data.data.translations;
870	    }
871	    return null;
872	  }
873	
874	  async function safeReadResponseText(resp) {
875	    try {
876	      return await resp.text();
877	    } catch (e) {
878	      return "";
879	    }
880	  }
881	
882	  // #SEC11: Decode the small set of entities Google Translate emits in
883	  // response text. Earlier this used `textarea.innerHTML = ...` which is
884	  // safe (textarea is RCDATA, content never parses as HTML), but the
885	  // pattern is review-hostile — it looks like an innerHTML sink even though
886	  // it isn't, and an unfamiliar reviewer might "fix" it the wrong way.
887	  // Explicit replacements remove that footgun. Includes numeric entities
888	  // because some translations come back with "&#39;" etc.
889	  function decodeHtmlEntities(text) {
890	    return safeStr(text)
891	      .replace(/&#(\d+);/g, function (_, n) {
892	        const code = parseInt(n, 10);
893	        return Number.isFinite(code) ? String.fromCodePoint(code) : "";
894	      })
895	      .replace(/&#x([0-9a-fA-F]+);/g, function (_, n) {
896	        const code = parseInt(n, 16);
897	        return Number.isFinite(code) ? String.fromCodePoint(code) : "";
898	      })
899	      .replace(/&quot;/g, '"')
900	      .replace(/&apos;/g, "'")
901	      .replace(/&lt;/g, "<")
902	      .replace(/&gt;/g, ">")
903	      .replace(/&amp;/g, "&");  // last so we don't double-decode
904	  }
905	
906	  function clampInt(v, min, max, fallback) {
907	    const n = Number(v);
908	    if (!Number.isFinite(n)) {
909	      return fallback;
910	    }
911	    return Math.max(min, Math.min(max, Math.round(n)));
912	  }
913	
914	  function sleep(ms) {
915	    return new Promise(resolve => {
916	      window.setTimeout(resolve, Math.max(0, Number(ms) || 0));
917	    });
918	  }
919	
920	  async function mapWithConcurrency(items, limit, mapper) {
921	    const list = Array.isArray(items) ? items : [];
922	    const cap = Math.max(1, Number(limit) || 1);
923	    const out = new Array(list.length);
924	    let cursor = 0;
925	
926	    async function worker() {
927	      let idx;
928	      while (true) {
929	        idx = cursor;
930	        cursor += 1;
931	        if (idx >= list.length) {
932	          return;
933	        }
934	        out[idx] = await mapper(list[idx], idx);
935	      }
936	    }
937	
938	    const workers = [];
939	    let i;
940	    for (i = 0; i < Math.min(cap, list.length); i += 1) {
941	      workers.push(worker());
942	    }
943	    await Promise.all(workers);
944	    return out;
945	  }
946	
947	  function safeStr(v) {
948	    return v === undefined || v === null ? "" : String(v);
949	  }
950	})();
