1	/**
2	 * Phase 7-SC convergence verification.
3	 *
4	 * Loads a real translation package, triggers preview render + PDF export with
5	 * state.fontDebug enabled, then asserts numerical thresholds from
6	 * task_plan.md Phase 7.4:
7	 *
8	 *   - PDF font sizes are within source point_size (no extreme shrinkage)
9	 *   - lineCount stable per segment across multiple renders
10	 *   - loadJsPdfFont source = "embedded" (file:// safety; here HTTP also fine)
11	 *   - phase7SkippedSegments[] is empty
12	 *
13	 * Fixture: pass via env PHASE7_FIXTURE_DIR or use the default below.
14	 *
15	 * Run:
16	 *   npx playwright test tests/phase7_sc_convergence.spec.js
17	 *
18	 * Override fixture:
19	 *   PHASE7_FIXTURE_DIR="C:/path/to/package" npx playwright test tests/phase7_sc_convergence.spec.js
20	 */
21	const path = require("path");
22	const fs = require("fs");
23	const { spawn } = require("child_process");
24	const { test, expect } = require("@playwright/test");
25	
26	const SERVE_JS = path.resolve(__dirname, "..", "..", "..", "serve.js");
27	const LAST_FOLDER_FILE = path.resolve(__dirname, "..", "..", "..", ".scratch", "last_folder.txt");
28	// Reports under .scratch/ so a single .gitignore entry covers them.
29	// (Pre-2026-05-02 wrote to <translator_app_checks>/reports/.)
30	const REPORT_DIR = path.resolve(__dirname, "..", ".scratch", "playwright", "phase7-reports");
31	
32	// Phase7 convergence test needs a real translation package fixture to compare
33	// preview vs PDF font sizes per-segment. The fixture is machine-specific and
34	// may contain confidential customer content â€” we don't ship one in-repo.
35	// Set PHASE7_FIXTURE_DIR env to a local package directory before running.
36	// Without it, the test SKIPS rather than failing CI (was previously
37	// hard-coded to a developer machine path which made CI red on any clone).
38	const FIXTURE = process.env.PHASE7_FIXTURE_DIR || "";
39	
40	const PORT = 14000 + Math.floor(Math.random() * 5000);
41	
42	let serverProc;
43	
44	test.beforeAll(async () => {
45	  if (!FIXTURE || !fs.existsSync(FIXTURE)) {
46	    test.skip(true,
47	      "PHASE7_FIXTURE_DIR not set or path missing â€” skipping Phase 7 " +
48	      "convergence test. Set env var to a real package directory to run."
49	    );
50	    return;
51	  }
52	  const segPath = path.join(FIXTURE, "segments.json");
53	  if (!fs.existsSync(segPath)) {
54	    test.skip(true, "Fixture missing segments.json: " + segPath);
55	    return;
56	  }
57	  try { fs.unlinkSync(LAST_FOLDER_FILE); } catch (_) {}
58	
59	  serverProc = spawn(process.execPath, [SERVE_JS, String(PORT)], {
60	    stdio: "pipe",
61	    cwd: path.dirname(SERVE_JS)
62	  });
63	
64	  let stderrBuf = "";
65	  serverProc.stderr.on("data", (d) => { stderrBuf += d.toString(); });
66	
67	  await new Promise((resolve, reject) => {
68	    const timeout = setTimeout(() => {
69	      reject(new Error("serve.js startup timeout. stderr: " + stderrBuf));
70	    }, 10000);
71	    serverProc.stdout.on("data", (d) => {
72	      if (d.toString().includes("http://")) { clearTimeout(timeout); resolve(); }
73	    });
74	    serverProc.on("close", (code) => {
75	      clearTimeout(timeout);
76	      reject(new Error("serve.js exited with code " + code + ". stderr: " + stderrBuf));
77	    });
78	    serverProc.on("error", (err) => { clearTimeout(timeout); reject(err); });
79	  });
80	});
81	
82	test.afterAll(async () => {
83	  if (serverProc) { serverProc.kill(); serverProc = null; }
84	});
85	
86	async function loadFixture(page) {
87	  await page.goto(`http://localhost:${PORT}/index.html`);
88	  await expect(page.locator("#cardsView")).toBeVisible({ timeout: 10000 });
89	  await page.evaluate(() => { window.state.fontDebug = true; window.state.fontDebugLog = []; });
90	  await page.evaluate(async (dirPath) => {
91	    await window.loadFolderFromServer(dirPath);
92	  }, FIXTURE);
93	  // Wait until segments load. The test fixture has many cards.
94	  await page.waitForFunction(
95	    () => window.state && window.state.segments && window.state.segments.length > 0,
96	    null,
97	    { timeout: 15000 }
98	  );
99	}
100	
101	test("phase7-sc: load + preview + PDF export, capture full diagnostic", async ({ page }) => {
102	  test.setTimeout(180000);  // 3 min â€” PDF export of large pkg can take time
103	
104	  await loadFixture(page);
105	
106	  // Trigger PDF rendering of multiple pages so preview hotspots get built.
107	  // Cycle through first ~5 pages to populate diagnostic log on each.
108	  const numPages = await page.evaluate(() => window.state.pdfDoc ? window.state.pdfDoc.numPages : 0);
109	  expect(numPages).toBeGreaterThan(0);
110	
111	  const pagesToVisit = Math.min(5, numPages);
112	  for (let p = 0; p < pagesToVisit; p++) {
113	    await page.evaluate((pi) => { window.state.currentPage = pi; window.renderPdf && window.renderPdf(); }, p);
114	    await page.waitForTimeout(500);
115	  }
116	
117	  // Trigger PDF export
118	  const exportBtn = page.locator("#exportPdfBtn");
119	  await expect(exportBtn).toBeVisible();
120	  // Listen for download to detect completion
121	  const downloadPromise = page.waitForEvent("download", { timeout: 120000 });
122	  await exportBtn.click();
123	  await downloadPromise;
124	
125	  // Pull diagnostics
126	  const diag = await page.evaluate(() => {
127	    return {
128	      log: window.state.fontDebugLog || [],
129	      skippedSegments: window.state.phase7SkippedSegments || [],
130	      cssPxPerPt: window.state.cssPxPerPt,
131	      preview7Enabled: window.state.phase7PreviewEnabled
132	    };
133	  });
134	
135	  // Persist a report on every run, regardless of pass/fail
136	  fs.mkdirSync(REPORT_DIR, { recursive: true });
137	  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
138	  const reportPath = path.join(REPORT_DIR, "phase7_sc_convergence_" + stamp + ".json");
139	  fs.writeFileSync(reportPath, JSON.stringify({
140	    fixture: FIXTURE,
141	    cssPxPerPt: diag.cssPxPerPt,
142	    preview7Enabled: diag.preview7Enabled,
143	    skippedSegments: diag.skippedSegments,
144	    counts: classifyLog(diag.log),
145	    pdfStats: pdfStats(diag.log),
146	    sampleDomMeasureRows: diag.log.filter(r => r.src === "dom_measure").slice(0, 20),
147	    samplePdfRows: diag.log.filter(r => r.src === "pdf").slice(0, 5),
148	    sampleLoadJsPdfFontRows: diag.log.filter(r => r.src === "loadJsPdfFont"),
149	    samplePdfPageRows: diag.log.filter(r => r.src === "pdf_page"),
150	    crossModeMatches: crossCorrelate(diag.log)
151	  }, null, 2), "utf-8");
152	  console.log("[phase7] report written:", reportPath);
153	
154	  // â”€â”€ Assertions â”€â”€
155	
156	  // 1. fontDebugLog is non-trivial
157	  expect(diag.log.length).toBeGreaterThan(50);
158	
159	  // 2. Phase 7 PDF path is active (dom_measure rows present)
160	  const dmPdf = diag.log.filter(r => r.src === "dom_measure" && (r.where === "pdf" || !r.where));
161	  expect(dmPdf.length).toBeGreaterThan(10);
162	
163	  // 3. No silent grapheme drops on PDF side
164	  expect(diag.skippedSegments.filter(s => !s.where || s.where === "pdf")).toHaveLength(0);
165	
166	  // 4. loadJsPdfFont uses embedded base64 (Phase 5 contract)
167	  const lf = diag.log.filter(r => r.src === "loadJsPdfFont");
168	  expect(lf.length).toBeGreaterThan(0);
169	  for (const r of lf) {
170	    expect(r.source).toBe("embedded");
171	  }
172	
173	  // 5. PDF font sizes never exceed maxFontSize (i.e. source point_size)
174	  for (const r of dmPdf) {
175	    if (typeof r.maxFontSize_pt === "number" && r.maxFontSize_pt > 0) {
176	      expect(r.fontSize_pt || r.fontSize).toBeLessThanOrEqual(r.maxFontSize_pt + 0.01);
177	    }
178	  }
179	
180	  // 6. Most PDF segments shouldn't shrink to less than 50% of maxFontSize
181	  // (a sanity-check; below this is usually pathological data like the
182	  // 5.6 outlier with leading_pt=44 on point_size=10)
183	  let extremeShrink = 0;
184	  for (const r of dmPdf) {
185	    const max = r.maxFontSize_pt || 0;
186	    const fs2 = r.fontSize_pt || r.fontSize || 0;
187	    if (max > 0 && fs2 > 0 && fs2 < max * 0.5) extremeShrink++;
188	  }
189	  // Allow up to 10% of segments to shrink heavily (5.6 outlier territory).
190	  expect(extremeShrink).toBeLessThanOrEqual(Math.ceil(dmPdf.length * 0.1));
191	});
192	
193	function crossCorrelate(log) {
194	  // For each tid that appears in BOTH preview and pdf dom_measure, compare
195	  // box dimensions in pt-equivalent units. Convergence target: ratios â‰ˆ 1.
196	  const pdfByTid = {};
197	  const previewByTid = {};
198	  for (const r of log) {
199	    if (r.src !== "dom_measure" || !r.tid) continue;
200	    if (r.where === "pdf") pdfByTid[r.tid] = r;
201	    else if (r.where === "preview") previewByTid[r.tid] = r;
202	  }
203	  const out = [];
204	  for (const tid in pdfByTid) {
205	    if (!previewByTid[tid]) continue;
206	    const p = pdfByTid[tid];
207	    const v = previewByTid[tid];
208	    const cssPxPerPt = v.cssPxPerPt || 1;
209	    const prevW_pt = v.boxW_cssPx / cssPxPerPt;
210	    const prevH_pt = v.boxH_cssPx / cssPxPerPt;
211	    out.push({
212	      tid: tid,
213	      text: (p.text || "").slice(0, 24),
214	      pdf: { w_pt: p.innerW_pt, h_pt: p.innerH_pt, fs_pt: p.fontSize_pt, lines: p.lineCount },
215	      preview: { w_pt: +prevW_pt.toFixed(2), h_pt: +prevH_pt.toFixed(2), fs_pt_eq: v.fontSize_pt_equiv, lines: v.lineCount },
216	      ratio_w: +(prevW_pt / p.innerW_pt).toFixed(3),
217	      ratio_h: +(prevH_pt / p.innerH_pt).toFixed(3),
218	      ratio_fs: +(v.fontSize_pt_equiv / p.fontSize_pt).toFixed(3)
219	    });
220	    if (out.length >= 30) break;
221	  }
222	  return out;
223	}
224	
225	function classifyLog(log) {
226	  const out = {};
227	  for (const r of log) {
228	    const k = r.src + (r.where ? ":" + r.where : "");
229	    out[k] = (out[k] || 0) + 1;
230	  }
231	  return out;
232	}
233	
