/**
 * Phase 7-SC convergence verification.
 *
 * Loads a real translation package, triggers preview render + PDF export with
 * state.fontDebug enabled, then asserts numerical thresholds from
 * task_plan.md Phase 7.4:
 *
 *   - PDF font sizes are within source point_size (no extreme shrinkage)
 *   - lineCount stable per segment across multiple renders
 *   - loadJsPdfFont source = "embedded" (file:// safety; here HTTP also fine)
 *   - phase7SkippedSegments[] is empty
 *
 * Fixture: pass via env PHASE7_FIXTURE_DIR or use the default below.
 *
 * Run:
 *   npx playwright test tests/phase7_sc_convergence.spec.js
 *
 * Override fixture:
 *   PHASE7_FIXTURE_DIR="C:/path/to/package" npx playwright test tests/phase7_sc_convergence.spec.js
 */
const path = require("path");
const fs = require("fs");
const { spawn } = require("child_process");
const { test, expect } = require("@playwright/test");

const SERVE_JS = path.resolve(__dirname, "..", "..", "..", "serve.js");
const LAST_FOLDER_FILE = path.resolve(__dirname, "..", "..", "..", ".scratch", "last_folder.txt");
// Reports under .scratch/ so a single .gitignore entry covers them.
// (Pre-2026-05-02 wrote to <translator_app_checks>/reports/.)
const REPORT_DIR = path.resolve(__dirname, "..", ".scratch", "playwright", "phase7-reports");

// Phase7 convergence test needs a real translation package fixture to compare
// preview vs PDF font sizes per-segment. The fixture is machine-specific and
// may contain confidential customer content â€” we don't ship one in-repo.
// Set PHASE7_FIXTURE_DIR env to a local package directory before running.
// Without it, the test SKIPS rather than failing CI (was previously
// hard-coded to a developer machine path which made CI red on any clone).
const FIXTURE = process.env.PHASE7_FIXTURE_DIR || "";

const PORT = 14000 + Math.floor(Math.random() * 5000);

let serverProc;

test.beforeAll(async () => {
  if (!FIXTURE || !fs.existsSync(FIXTURE)) {
    test.skip(true,
      "PHASE7_FIXTURE_DIR not set or path missing â€” skipping Phase 7 " +
      "convergence test. Set env var to a real package directory to run."
    );
    return;
  }
  const segPath = path.join(FIXTURE, "segments.json");
  if (!fs.existsSync(segPath)) {
    test.skip(true, "Fixture missing segments.json: " + segPath);
    return;
  }
  try { fs.unlinkSync(LAST_FOLDER_FILE); } catch (_) {}

  serverProc = spawn(process.execPath, [SERVE_JS, String(PORT)], {
    stdio: "pipe",
    cwd: path.dirname(SERVE_JS)
  });

  let stderrBuf = "";
  serverProc.stderr.on("data", (d) => { stderrBuf += d.toString(); });

  await new Promise((resolve, reject) => {
    const timeout = setTimeout(() => {
      reject(new Error("serve.js startup timeout. stderr: " + stderrBuf));
    }, 10000);
    serverProc.stdout.on("data", (d) => {
      if (d.toString().includes("http://")) { clearTimeout(timeout); resolve(); }
    });
    serverProc.on("close", (code) => {
      clearTimeout(timeout);
      reject(new Error("serve.js exited with code " + code + ". stderr: " + stderrBuf));
    });
    serverProc.on("error", (err) => { clearTimeout(timeout); reject(err); });
  });
});

test.afterAll(async () => {
  if (serverProc) { serverProc.kill(); serverProc = null; }
});

async function loadFixture(page) {
  await page.goto(`http://localhost:${PORT}/index.html`);
  await expect(page.locator("#cardsView")).toBeVisible({ timeout: 10000 });
  await page.evaluate(() => { window.state.fontDebug = true; window.state.fontDebugLog = []; });
  await page.evaluate(async (dirPath) => {
    await window.loadFolderFromServer(dirPath);
  }, FIXTURE);
  // Wait until segments load. The test fixture has many cards.
  await page.waitForFunction(
    () => window.state && window.state.segments && window.state.segments.length > 0,
    null,
    { timeout: 15000 }
  );
}

test("phase7-sc: load + preview + PDF export, capture full diagnostic", async ({ page }) => {
  test.setTimeout(180000);  // 3 min â€” PDF export of large pkg can take time

  await loadFixture(page);

  // Trigger PDF rendering of multiple pages so preview hotspots get built.
  // Cycle through first ~5 pages to populate diagnostic log on each.
  const numPages = await page.evaluate(() => window.state.pdfDoc ? window.state.pdfDoc.numPages : 0);
  expect(numPages).toBeGreaterThan(0);

  const pagesToVisit = Math.min(5, numPages);
  for (let p = 0; p < pagesToVisit; p++) {
    await page.evaluate((pi) => { window.state.currentPage = pi; window.renderPdf && window.renderPdf(); }, p);
    await page.waitForTimeout(500);
  }

  // Trigger PDF export
  const exportBtn = page.locator("#exportPdfBtn");
  await expect(exportBtn).toBeVisible();
  // Listen for download to detect completion
  const downloadPromise = page.waitForEvent("download", { timeout: 120000 });
  await exportBtn.click();
  await downloadPromise;

  // Pull diagnostics
  const diag = await page.evaluate(() => {
    return {
      log: window.state.fontDebugLog || [],
      skippedSegments: window.state.phase7SkippedSegments || [],
      cssPxPerPt: window.state.cssPxPerPt,
      preview7Enabled: window.state.phase7PreviewEnabled
    };
  });

  // Persist a report on every run, regardless of pass/fail
  fs.mkdirSync(REPORT_DIR, { recursive: true });
  const stamp = new Date().toISOString().replace(/[:.]/g, "-");
  const reportPath = path.join(REPORT_DIR, "phase7_sc_convergence_" + stamp + ".json");
  fs.writeFileSync(reportPath, JSON.stringify({
    fixture: FIXTURE,
    cssPxPerPt: diag.cssPxPerPt,
    preview7Enabled: diag.preview7Enabled,
    skippedSegments: diag.skippedSegments,
    counts: classifyLog(diag.log),
    pdfStats: pdfStats(diag.log),
    sampleDomMeasureRows: diag.log.filter(r => r.src === "dom_measure").slice(0, 20),
    samplePdfRows: diag.log.filter(r => r.src === "pdf").slice(0, 5),
    sampleLoadJsPdfFontRows: diag.log.filter(r => r.src === "loadJsPdfFont"),
    samplePdfPageRows: diag.log.filter(r => r.src === "pdf_page"),
    crossModeMatches: crossCorrelate(diag.log)
  }, null, 2), "utf-8");
  console.log("[phase7] report written:", reportPath);

  // â”€â”€ Assertions â”€â”€

  // 1. fontDebugLog is non-trivial
  expect(diag.log.length).toBeGreaterThan(50);

  // 2. Phase 7 PDF path is active (dom_measure rows present)
  const dmPdf = diag.log.filter(r => r.src === "dom_measure" && (r.where === "pdf" || !r.where));
  expect(dmPdf.length).toBeGreaterThan(10);

  // 3. No silent grapheme drops on PDF side
  expect(diag.skippedSegments.filter(s => !s.where || s.where === "pdf")).toHaveLength(0);

  // 4. loadJsPdfFont uses embedded base64 (Phase 5 contract)
  const lf = diag.log.filter(r => r.src === "loadJsPdfFont");
  expect(lf.length).toBeGreaterThan(0);
  for (const r of lf) {
    expect(r.source).toBe("embedded");
  }

  // 5. PDF font sizes never exceed maxFontSize (i.e. source point_size)
  for (const r of dmPdf) {
    if (typeof r.maxFontSize_pt === "number" && r.maxFontSize_pt > 0) {
      expect(r.fontSize_pt || r.fontSize).toBeLessThanOrEqual(r.maxFontSize_pt + 0.01);
    }
  }

  // 6. Most PDF segments shouldn't shrink to less than 50% of maxFontSize
  // (a sanity-check; below this is usually pathological data like the
  // 5.6 outlier with leading_pt=44 on point_size=10)
  let extremeShrink = 0;
  for (const r of dmPdf) {
    const max = r.maxFontSize_pt || 0;
    const fs2 = r.fontSize_pt || r.fontSize || 0;
    if (max > 0 && fs2 > 0 && fs2 < max * 0.5) extremeShrink++;
  }
  // Allow up to 10% of segments to shrink heavily (5.6 outlier territory).
  expect(extremeShrink).toBeLessThanOrEqual(Math.ceil(dmPdf.length * 0.1));
});

function crossCorrelate(log) {
  // For each tid that appears in BOTH preview and pdf dom_measure, compare
  // box dimensions in pt-equivalent units. Convergence target: ratios â‰ˆ 1.
  const pdfByTid = {};
  const previewByTid = {};
  for (const r of log) {
    if (r.src !== "dom_measure" || !r.tid) continue;
    if (r.where === "pdf") pdfByTid[r.tid] = r;
    else if (r.where === "preview") previewByTid[r.tid] = r;
  }
  const out = [];
  for (const tid in pdfByTid) {
    if (!previewByTid[tid]) continue;
    const p = pdfByTid[tid];
    const v = previewByTid[tid];
    const cssPxPerPt = v.cssPxPerPt || 1;
    const prevW_pt = v.boxW_cssPx / cssPxPerPt;
    const prevH_pt = v.boxH_cssPx / cssPxPerPt;
    out.push({
      tid: tid,
      text: (p.text || "").slice(0, 24),
      pdf: { w_pt: p.innerW_pt, h_pt: p.innerH_pt, fs_pt: p.fontSize_pt, lines: p.lineCount },
      preview: { w_pt: +prevW_pt.toFixed(2), h_pt: +prevH_pt.toFixed(2), fs_pt_eq: v.fontSize_pt_equiv, lines: v.lineCount },
      ratio_w: +(prevW_pt / p.innerW_pt).toFixed(3),
      ratio_h: +(prevH_pt / p.innerH_pt).toFixed(3),
      ratio_fs: +(v.fontSize_pt_equiv / p.fontSize_pt).toFixed(3)
    });
    if (out.length >= 30) break;
  }
  return out;
}

function classifyLog(log) {
  const out = {};
  for (const r of log) {
    const k = r.src + (r.where ? ":" + r.where : "");
    out[k] = (out[k] || 0) + 1;
  }
  return out;
}

function pdfStats(log) {
  const dm = log.filter(r => r.src === "dom_measure" && (!r.where || r.where === "pdf"));
  if (dm.length === 0) return { count: 0 };
  const fontSizes = dm.map(r => r.fontSize_pt || r.fontSize || 0).filter(x => x > 0);
  const lineCounts = dm.map(r => r.lineCount || 0);
  const fallbacks = dm.filter(r => r.metricsSource === "fallback").length;
  fontSizes.sort((a, b) => a - b);
  return {
    count: dm.length,
    fontSize_min: fontSizes[0],
    fontSize_p50: fontSizes[Math.floor(fontSizes.length * 0.5)],
    fontSize_max: fontSizes[fontSizes.length - 1],
    lineCount_min: Math.min(...lineCounts),
    lineCount_max: Math.max(...lineCounts),
    fallback_metrics_count: fallbacks
  };
}

