/**
 * Source-extracted test for diffEditRange + adjustAnnotationOffsets (Phase 3).
 * Run: node test_adjustAnnotationOffsets.js
 */
var fs = require("fs");
var path = require("path");
var vm = require("vm");

var appSrc = fs.readFileSync(path.join(__dirname, "app.js"), "utf8");

function extractFunction(src, name) {
  var idx = src.indexOf("function " + name + "(");
  if (idx < 0) throw new Error("Function " + name + " not found in app.js");
  var braceStart = src.indexOf("{", idx);
  if (braceStart < 0) throw new Error("No opening brace for " + name);
  var depth = 0, i = braceStart;
  for (; i < src.length; i++) {
    if (src[i] === "{") depth++;
    else if (src[i] === "}") { depth--; if (depth === 0) break; }
  }
  return src.substring(idx, i + 1);
}

var sandbox = {};
var fnNames = ["diffEditRange", "adjustAnnotationOffsets"];
var combinedSrc = fnNames.map(function (n) { return extractFunction(appSrc, n); }).join("\n\n");
combinedSrc += "\nthis.diffEditRange = diffEditRange;\nthis.adjustAnnotationOffsets = adjustAnnotationOffsets;";
vm.runInNewContext(combinedSrc, sandbox);
var diffEditRange = sandbox.diffEditRange;
var adjustAnnotationOffsets = sandbox.adjustAnnotationOffsets;

console.log("OK: extracted diffEditRange + adjustAnnotationOffsets from app.js\n");

var passed = 0, failed = 0;
function assert(label, actual, expected) {
  var a = JSON.stringify(actual), e = JSON.stringify(expected);
  if (a === e) { passed++; console.log("  PASS: " + label); }
  else { failed++; console.log("  FAIL: " + label); console.log("    expected: " + e); console.log("    actual:   " + a); }
}

// ── diffEditRange tests ──
console.log("diffEditRange tests:");

assert("identical", diffEditRange("abc", "abc"), { editOffset: 0, deleteCount: 0, insertCount: 0 });
assert("insert at end", diffEditRange("abc", "abcd"), { editOffset: 3, deleteCount: 0, insertCount: 1 });
assert("insert in middle", diffEditRange("abcd", "abXcd"), { editOffset: 2, deleteCount: 0, insertCount: 1 });
assert("delete one char", diffEditRange("abcd", "acd"), { editOffset: 1, deleteCount: 1, insertCount: 0 });
assert("replace range", diffEditRange("abcd", "aXYZd"), { editOffset: 1, deleteCount: 2, insertCount: 3 });
assert("delete all", diffEditRange("abc", ""), { editOffset: 0, deleteCount: 3, insertCount: 0 });
assert("insert into empty", diffEditRange("", "abc"), { editOffset: 0, deleteCount: 0, insertCount: 3 });
assert("CJK insert space", diffEditRange("你好世界测试文本", "你好世界 测试文本"), { editOffset: 4, deleteCount: 0, insertCount: 1 });

// ── adjustAnnotationOffsets tests ──
console.log("\nadjustAnnotationOffsets tests:");

// Helper
function ann(action, offset, length) {
  return { type: "format", action: action, text: "", offset: offset, length: length };
}
function pick(a) { return { offset: a.offset, length: a.length, text: a.text }; }

// T1: insert before annotation → shift
var r1 = adjustAnnotationOffsets(
  [ann("bold", 4, 2)], 0, 0, 1, "X你好世界测试"
);
assert("insert before → shift", pick(r1[0]), { offset: 5, length: 2, text: "测试" });

// T2: insert after annotation → no change
var r2 = adjustAnnotationOffsets(
  [ann("bold", 0, 2)], 5, 0, 1, "你好世界测X试"
);
assert("insert after → no change", pick(r2[0]), { offset: 0, length: 2, text: "你好" });

// T3: insert inside annotation → length grows
var r3 = adjustAnnotationOffsets(
  [ann("bold", 0, 4)], 2, 0, 1, "你好X世界"
);
assert("insert inside → length grows", pick(r3[0]), { offset: 0, length: 5, text: "你好X世界" });

// T4: delete inside annotation → length shrinks
var r4 = adjustAnnotationOffsets(
  [ann("bold", 0, 4)], 1, 1, 0, "你世界"
);
assert("delete inside → length shrinks", pick(r4[0]), { offset: 0, length: 3, text: "你世界" });

// T5: delete entire annotation → removed
var r5 = adjustAnnotationOffsets(
  [ann("bold", 2, 2)], 2, 2, 0, "你好文本"
);
assert("delete entire → removed", r5.length, 0);

// T6: CJK space insert between adjacent annotations
//     "你好世界测试文本" → "你好世界 测试文本"
//     bold[0,2) italic[2,4) color[4,6) comment[6,8)
var anns6 = [
  { type: "format", action: "bold", text: "你好", offset: 0, length: 2 },
  { type: "format", action: "italic", text: "世界", offset: 2, length: 2 },
  { type: "format", action: "color", text: "测试", offset: 4, length: 2 },
  { type: "comment", action: "", text: "文本", offset: 6, length: 2 }
];
var r6 = adjustAnnotationOffsets(anns6, 4, 0, 1, "你好世界 测试文本");
assert("space between annotations: bold unchanged", pick(r6[0]), { offset: 0, length: 2, text: "你好" });
assert("space between annotations: italic unchanged", pick(r6[1]), { offset: 2, length: 2, text: "世界" });
assert("space between annotations: color shifted", pick(r6[2]), { offset: 5, length: 2, text: "测试" });
assert("space between annotations: comment shifted", pick(r6[3]), { offset: 7, length: 2, text: "文本" });

// T7: delete char before annotation → shift back
var r7 = adjustAnnotationOffsets(
  [ann("bold", 3, 2)], 0, 1, 0, "好世界测试"
);
assert("delete before → shift back", pick(r7[0]), { offset: 2, length: 2, text: "界测" });

// T8: replace across annotation boundary → partial survive
var r8 = adjustAnnotationOffsets(
