/**
 * Source-extracted test for buildOverlayHtml (Phase 1).
 * Extracts the real functions from app.js at runtime — no mirror copy.
 * Run: node test_buildOverlayHtml.js
 */

var fs = require("fs");
var path = require("path");
var vm = require("vm");

// ── Load real app.js source and extract functions ──
var appSrc = fs.readFileSync(path.join(__dirname, "app.js"), "utf8");

// Extract named functions from source by regex.
// This pulls the real implementation, not a mirror copy.
function extractFunction(src, name) {
  // Match "function name(...) { ... }" at top level (not indented inside another function body
  // that starts at column 0). We find the function start, then brace-match to find the end.
  var idx = src.indexOf("function " + name + "(");
  if (idx < 0) throw new Error("Function " + name + " not found in app.js");
  var braceStart = src.indexOf("{", idx);
  if (braceStart < 0) throw new Error("No opening brace for " + name);
  var depth = 0;
  var i = braceStart;
  for (; i < src.length; i++) {
    if (src[i] === "{") depth++;
    else if (src[i] === "}") { depth--; if (depth === 0) break; }
  }
  return src.substring(idx, i + 1);
}

// Build a sandbox with the required functions from app.js
var fnNames = ["safeStr", "escapeHtmlText", "escapeHtmlAttr", "tokenAwareHtml", "buildOverlayHtml"];
var sandbox = {};
var combinedSrc = fnNames.map(function (n) { return extractFunction(appSrc, n); }).join("\n\n");
// Expose buildOverlayHtml to the outer scope via the sandbox
combinedSrc += "\n\nthis.buildOverlayHtml = buildOverlayHtml;";
vm.runInNewContext(combinedSrc, sandbox);
var buildOverlayHtml = sandbox.buildOverlayHtml;

if (typeof buildOverlayHtml !== "function") {
  console.error("FATAL: buildOverlayHtml was not extracted from app.js");
  process.exit(2);
}
console.log("OK: extracted real buildOverlayHtml + dependencies from app.js\n");

// ── Test harness ──
var passed = 0, failed = 0;
function assert(label, actual, expected) {
  if (actual === expected) {
    passed++;
    console.log("  PASS: " + label);
  } else {
    failed++;
    console.log("  FAIL: " + label);
    console.log("    expected: " + expected);
    console.log("    actual:   " + actual);
  }
}

// ── Helper to build expected span ──
function annSpan(idx, type, action, content) {
  return '<span class="ann-highlight" data-ann-idx="' + idx +
    '" data-ann-type="' + type +
    '" data-ann-action="' + action + '">' + content + '</span>';
}

// ── Tests ──
console.log("buildOverlayHtml tests (source-extracted):");

// T1: empty input
assert("empty string", buildOverlayHtml("", []), "");

// T2: no annotations, no tokens → plain escaped text
assert("plain text, no annotations", buildOverlayHtml("hello", []), "hello");

// T3: no annotations, has token → tokenAwareHtml path
assert("token only",
  buildOverlayHtml("a{PAGE_CURRENT}b", []),
  'a<span class="token-inline">{PAGE_CURRENT}</span>b');

// T4: bold annotation — unified class, data attrs carry type info
assert("bold annotation",
  buildOverlayHtml("hello world", [{ type: "format", action: "bold", offset: 0, length: 5, text: "hello" }]),
  annSpan(0, "format", "bold", "hello") + ' world');

// T5: italic annotation mid-text
assert("italic annotation",
  buildOverlayHtml("abc def ghi", [{ type: "format", action: "italic", offset: 4, length: 3, text: "def" }]),
  'abc ' + annSpan(0, "format", "italic", "def") + ' ghi');

// T6: superscript
assert("superscript annotation",
  buildOverlayHtml("x2y", [{ type: "format", action: "superscript", offset: 1, length: 1, text: "2" }]),
  'x' + annSpan(0, "format", "superscript", "2") + 'y');

// T7: color annotation — no inline style, unified class
assert("color annotation",
  buildOverlayHtml("red text", [{ type: "format", action: "color", offset: 0, length: 3, text: "red", color: "#ff0000" }]),
  annSpan(0, "format", "color", "red") + ' text');

// T8: comment annotation — same unified class
assert("comment annotation",
  buildOverlayHtml("some note here", [{ type: "comment", action: "", offset: 5, length: 4, text: "note" }]),
  'some ' + annSpan(0, "comment", "", "note") + ' here');

// T9: token + annotation (non-overlapping)
assert("token + annotation separate",
  buildOverlayHtml("{PAGE_CURRENT} bold", [{ type: "format", action: "bold", offset: 15, length: 4, text: "bold" }]),
  '<span class="token-inline">{PAGE_CURRENT}</span> ' + annSpan(0, "format", "bold", "bold"));

// T10: overlapping annotations — stable nesting: wider range is outer
assert("overlapping — wider range is outer",
  buildOverlayHtml("abcdef", [
    { type: "format", action: "italic", offset: 2, length: 3, text: "cde" },
    { type: "format", action: "bold", offset: 1, length: 4, text: "bcde" }
  ]),
  'a' +
  annSpan(1, "format", "bold", "b") +
  annSpan(1, "format", "bold", annSpan(0, "format", "italic", "cde")) +
  'f');

// T11: overlapping same-width — format outermost, comment innermost
assert("overlapping same-width: format outer, comment inner",
  buildOverlayHtml("abc", [
    { type: "comment", action: "", offset: 0, length: 3, text: "abc" },
    { type: "format", action: "bold", offset: 0, length: 3, text: "abc" }
  ]),
  annSpan(1, "format", "bold", annSpan(0, "comment", "", "abc")));

// T12: annotation out of bounds → ignored
assert("out-of-bounds annotation ignored",
  buildOverlayHtml("hi", [{ type: "format", action: "bold", offset: 0, length: 10, text: "hi" }]),
  'hi');

// T13: annotation at exact text boundary
assert("annotation at exact bounds",
  buildOverlayHtml("abc", [{ type: "format", action: "bold", offset: 0, length: 3, text: "abc" }]),
  annSpan(0, "format", "bold", "abc"));

// T14: HTML special chars in text are escaped
assert("HTML chars escaped",
  buildOverlayHtml("<b>hi</b>", [{ type: "format", action: "bold", offset: 0, length: 3, text: "<b>" }]),
  annSpan(0, "format", "bold", "&lt;b&gt;") + 'hi&lt;/b&gt;');

// T15: multiple non-overlapping annotations
assert("multiple non-overlapping",
  buildOverlayHtml("aabbcc", [
    { type: "format", action: "bold", offset: 0, length: 2, text: "aa" },
    { type: "format", action: "italic", offset: 4, length: 2, text: "cc" }
  ]),
  annSpan(0, "format", "bold", "aa") + 'bb' + annSpan(1, "format", "italic", "cc"));

// T16: creation order doesn't affect nesting (reversed input of T10)
assert("creation order irrelevant for nesting",
  buildOverlayHtml("abcdef", [
    { type: "format", action: "bold", offset: 1, length: 4, text: "bcde" },
    { type: "format", action: "italic", offset: 2, length: 3, text: "cde" }
  ]),
  'a' +
  annSpan(0, "format", "bold", "b") +
  annSpan(0, "format", "bold", annSpan(1, "format", "italic", "cde")) +
  'f');

console.log("\n" + passed + " passed, " + failed + " failed");
process.exit(failed > 0 ? 1 : 0);

