3	// translator_app/test_emphasis_overlay.js
4	//
5	// Tests for translator_app/lib/emphasis_overlay.js — the format-paint
6	// scaffolding that renders source emphasis HTML and suggests target
7	// emphasis offsets via heuristic alignment.
8	//
9	// Run: node test_emphasis_overlay.js
10	
11	var EO = require("./lib/emphasis_overlay.js");
12	
13	var failures = [];
14	var passed   = 0;
15	function assert(cond, msg) { if (cond) passed++; else failures.push(msg); }
16	function assertEq(a, b, msg) {
17	    if (a === b) { passed++; return; }
18	    failures.push(msg + " — expected " + JSON.stringify(b) + ", got " + JSON.stringify(a));
19	}
20	
21	// ─── renderEmphasisHtml ───────────────────────────────────────────
22	
23	(function test_render_no_runs() {
24	    assertEq(EO.renderEmphasisHtml("Hello", []),    "Hello",        "no runs → plain text");
25	    assertEq(EO.renderEmphasisHtml("a < b", []),    "a &lt; b",     "HTML-escapes < and >");
26	    assertEq(EO.renderEmphasisHtml("a & b", null),  "a &amp; b",    "HTML-escapes &");
27	    assertEq(EO.renderEmphasisHtml("", [{ start: 0, end: 1, diff: {} }]), "", "empty text → empty");
28	})();
29	
30	(function test_render_single_bold() {
31	    var html = EO.renderEmphasisHtml(
32	        "Hello world",
33	        [{ start: 6, end: 11, diff: { fontStyle: "Bold" } }]
34	    );
35	    assert(html.indexOf("Hello ") === 0,                       "render: prefix preserved");
36	    assert(html.indexOf('<span class="emp"') >= 0,             "render: emphasis span emitted");
37	    // No inline visual styles (the new design defers visual to CSS only).
38	    assert(html.indexOf("font-weight:700") < 0,                "render: NO inline bold style (CSS-only)");
39	    assert(html.indexOf("style=") < 0,                         "render: NO style= attr at all");
40	    assert(html.indexOf('data-emp-idx="0"') >= 0,              "render: data-emp-idx for click lookup");
41	    assert(html.indexOf(">world</span>") >= 0,                 "render: span wraps emphasized text");
42	})();
43	
44	(function test_render_with_tid() {
45	    var html = EO.renderEmphasisHtml(
46	        "Hello world",
47	        [{ start: 6, end: 11, diff: { fontStyle: "Bold" } }],
48	        "T-42"
49	    );
50	    assert(html.indexOf('data-emp-tid="T-42"') >= 0,           "render: tid plumbed via data-emp-tid");
51	})();
52	
53	(function test_render_multiple_runs() {
54	    var html = EO.renderEmphasisHtml(
55	        "AAA BBB CCC",
56	        [
57	            { start: 0, end: 3, diff: { fontStyle: "Bold" } },
58	            { start: 8, end: 11, diff: { underline: true } }
59	        ]
60	    );
61	    var spanCount = (html.match(/<span class="emp"/g) || []).length;
62	    assertEq(spanCount, 2, "multi-runs: 2 spans");
63	    assert(html.indexOf('data-emp-idx="0"') >= 0, "multi-runs: idx 0");
64	    assert(html.indexOf('data-emp-idx="1"') >= 0, "multi-runs: idx 1");
65	    assert(html.indexOf("style=") < 0,                  "multi-runs: still no inline styles");
66	})();
67	
68	(function test_render_idx_preserved_after_sort() {
69	    // Runs given out-of-order — internal sort happens but original idx must follow each run.
70	    var html = EO.renderEmphasisHtml(
71	        "AAA BBB CCC",
72	        [
73	            { start: 8, end: 11, diff: { underline: true } },     // origIdx 0
74	            { start: 0, end: 3, diff: { fontStyle: "Bold" } }      // origIdx 1
75	        ]
76	    );
77	    // First DOM-order span is "AAA" (the Bold one) which had original idx=1
78	    var firstSpanMatch = html.match(/<span class="emp"\s+data-emp-idx="(\d+)"[^>]*>AAA<\/span>/);
79	    assert(firstSpanMatch !== null, "sort: AAA span found");
80	    assertEq(firstSpanMatch[1], "1", "sort: AAA has origIdx=1 (preserved through internal sort)");
81	})();
82	
83	(function test_render_run_title_label() {
84	    var html = EO.renderEmphasisHtml("text", [{
85	        start: 0, end: 4, diff: { fontStyle: "Bold Italic", underline: true }
86	    }]);
87	    assert(html.indexOf('title="Bold + Italic + Underline"') >= 0,
88	           "render: title label describes diff");
89	})();
90	
91	// ─── describeRun ──────────────────────────────────────────────────
92	
93	(function test_describe_run() {
94	    assertEq(EO.describeRun({ diff: { fontStyle: "Bold" } }),       "Bold",      "describe: bold");
95	    assertEq(EO.describeRun({ diff: { fontStyle: "Italic" } }),     "Italic",    "describe: italic");
96	    assertEq(EO.describeRun({ diff: { underline: true } }),         "Underline", "describe: underline");
97	    assertEq(EO.describeRun({ diff: {
98	        fontStyle: "Bold", underline: true,
99	        fillColor: { values: [220, 30, 30], space: "RGB" }
100	    } }), "Bold + Underline + Color #DC1E1E", "describe: combined");
101	    assertEq(EO.describeRun({ diff: { baseline_shift: -2 } }),     "Subscript",  "describe: subscript");
102	    assertEq(EO.describeRun({ diff: { baseline_shift: 2 } }),      "Superscript", "describe: superscript");
103	    // fontFamily intentionally omitted from human label (multi-script split
104	    // is handled by import-side GREP rules, not as a paintable emphasis)
105	    assertEq(EO.describeRun({ diff: { fontFamily: "Arial" } }),    "",          "describe: fontFamily-only → empty label");
106	    assertEq(EO.describeRun({ diff: { fontStyle: "Italic", fontFamily: "Arial" } }),
107	             "Italic",                                                          "describe: mixed → only non-font dims");
108	})();
109	
110	// ─── fontFamily filtering ─────────────────────────────────────────
111	
112	(function test_render_skips_fontfamily_only_runs() {
113	    // F07-style segment: only fontFamily diff (CJK on YaHei + Latin on Arial,
114	    // no other dim). Webapp should NOT highlight — handled by import GREP.
115	    var html = EO.renderEmphasisHtml(
