134	(function test_diffHasVisibleEmphasis() {
135	    var fn = EO._internal.diffHasVisibleEmphasis;
136	    assertEq(fn({ fontStyle: "Bold" }),        true,  "visible: bold");
137	    assertEq(fn({ underline: true }),          true,  "visible: underline=true");
