142	    assertEq(fn({}),                           false, "visible: empty diff → false");
143	    assertEq(fn(null),                         false, "visible: null → false");
144	})();
145	
146	// ─── suggestTargetEmphasisRuns: exact substring tier ──────────────
147	
148	(function test_suggest_exact_match() {
149	    var result = EO.suggestTargetEmphasisRuns(
150	        "Our flagship product, Quantix Pro, is engineered.",
