"use strict";

// translator_app/test_emphasis_overlay.js
//
// Tests for translator_app/lib/emphasis_overlay.js — the format-paint
// scaffolding that renders source emphasis HTML and suggests target
// emphasis offsets via heuristic alignment.
//
// Run: node test_emphasis_overlay.js

var EO = require("./lib/emphasis_overlay.js");

var failures = [];
var passed   = 0;
function assert(cond, msg) { if (cond) passed++; else failures.push(msg); }
function assertEq(a, b, msg) {
    if (a === b) { passed++; return; }
    failures.push(msg + " — expected " + JSON.stringify(b) + ", got " + JSON.stringify(a));
}

// ─── renderEmphasisHtml ───────────────────────────────────────────

(function test_render_no_runs() {
    assertEq(EO.renderEmphasisHtml("Hello", []),    "Hello",        "no runs → plain text");
    assertEq(EO.renderEmphasisHtml("a < b", []),    "a &lt; b",     "HTML-escapes < and >");
    assertEq(EO.renderEmphasisHtml("a & b", null),  "a &amp; b",    "HTML-escapes &");
    assertEq(EO.renderEmphasisHtml("", [{ start: 0, end: 1, diff: {} }]), "", "empty text → empty");
})();

(function test_render_single_bold() {
    var html = EO.renderEmphasisHtml(
        "Hello world",
        [{ start: 6, end: 11, diff: { fontStyle: "Bold" } }]
    );
    assert(html.indexOf("Hello ") === 0,                       "render: prefix preserved");
    assert(html.indexOf('<span class="emp"') >= 0,             "render: emphasis span emitted");
    // No inline visual styles (the new design defers visual to CSS only).
    assert(html.indexOf("font-weight:700") < 0,                "render: NO inline bold style (CSS-only)");
    assert(html.indexOf("style=") < 0,                         "render: NO style= attr at all");
    assert(html.indexOf('data-emp-idx="0"') >= 0,              "render: data-emp-idx for click lookup");
    assert(html.indexOf(">world</span>") >= 0,                 "render: span wraps emphasized text");
})();

(function test_render_with_tid() {
    var html = EO.renderEmphasisHtml(
        "Hello world",
        [{ start: 6, end: 11, diff: { fontStyle: "Bold" } }],
        "T-42"
    );
    assert(html.indexOf('data-emp-tid="T-42"') >= 0,           "render: tid plumbed via data-emp-tid");
})();

(function test_render_multiple_runs() {
    var html = EO.renderEmphasisHtml(
        "AAA BBB CCC",
        [
            { start: 0, end: 3, diff: { fontStyle: "Bold" } },
            { start: 8, end: 11, diff: { underline: true } }
        ]
    );
    var spanCount = (html.match(/<span class="emp"/g) || []).length;
    assertEq(spanCount, 2, "multi-runs: 2 spans");
    assert(html.indexOf('data-emp-idx="0"') >= 0, "multi-runs: idx 0");
    assert(html.indexOf('data-emp-idx="1"') >= 0, "multi-runs: idx 1");
    assert(html.indexOf("style=") < 0,                  "multi-runs: still no inline styles");
})();

(function test_render_idx_preserved_after_sort() {
    // Runs given out-of-order — internal sort happens but original idx must follow each run.
    var html = EO.renderEmphasisHtml(
        "AAA BBB CCC",
        [
            { start: 8, end: 11, diff: { underline: true } },     // origIdx 0
            { start: 0, end: 3, diff: { fontStyle: "Bold" } }      // origIdx 1
        ]
    );
    // First DOM-order span is "AAA" (the Bold one) which had original idx=1
    var firstSpanMatch = html.match(/<span class="emp"\s+data-emp-idx="(\d+)"[^>]*>AAA<\/span>/);
    assert(firstSpanMatch !== null, "sort: AAA span found");
    assertEq(firstSpanMatch[1], "1", "sort: AAA has origIdx=1 (preserved through internal sort)");
})();

(function test_render_run_title_label() {
    var html = EO.renderEmphasisHtml("text", [{
        start: 0, end: 4, diff: { fontStyle: "Bold Italic", underline: true }
    }]);
    assert(html.indexOf('title="Bold + Italic + Underline"') >= 0,
           "render: title label describes diff");
})();

// ─── describeRun ──────────────────────────────────────────────────

(function test_describe_run() {
    assertEq(EO.describeRun({ diff: { fontStyle: "Bold" } }),       "Bold",      "describe: bold");
    assertEq(EO.describeRun({ diff: { fontStyle: "Italic" } }),     "Italic",    "describe: italic");
    assertEq(EO.describeRun({ diff: { underline: true } }),         "Underline", "describe: underline");
    assertEq(EO.describeRun({ diff: {
        fontStyle: "Bold", underline: true,
        fillColor: { values: [220, 30, 30], space: "RGB" }
    } }), "Bold + Underline + Color #DC1E1E", "describe: combined");
    assertEq(EO.describeRun({ diff: { baseline_shift: -2 } }),     "Subscript",  "describe: subscript");
    assertEq(EO.describeRun({ diff: { baseline_shift: 2 } }),      "Superscript", "describe: superscript");
    // fontFamily intentionally omitted from human label (multi-script split
    // is handled by import-side GREP rules, not as a paintable emphasis)
    assertEq(EO.describeRun({ diff: { fontFamily: "Arial" } }),    "",          "describe: fontFamily-only → empty label");
    assertEq(EO.describeRun({ diff: { fontStyle: "Italic", fontFamily: "Arial" } }),
             "Italic",                                                          "describe: mixed → only non-font dims");
})();

// ─── fontFamily filtering ─────────────────────────────────────────

(function test_render_skips_fontfamily_only_runs() {
    // F07-style segment: only fontFamily diff (CJK on YaHei + Latin on Arial,
    // no other dim). Webapp should NOT highlight — handled by import GREP.
    var html = EO.renderEmphasisHtml(
        "我们的产品 Arial Word 提供卓越性能",
        [{ start: 6, end: 16, diff: { fontFamily: "Arial" } }]
    );
    assertEq(html.indexOf("class=\"emp\""), -1, "ff-only: no .emp span emitted");
    assertEq(html.indexOf("Arial Word") >= 0, true, "ff-only: text still present");
})();

(function test_render_keeps_fontfamily_when_combined_with_others() {
    // F10-style: italic + fontFamily — webapp shows the italic, drops font
    var html = EO.renderEmphasisHtml(
        "本协议中定义的术语 Vextor Compact 解释。",
        [{ start: 11, end: 25, diff: { fontStyle: "Italic", fontFamily: "Arial" } }]
    );
    assert(html.indexOf("class=\"emp\"") >= 0,    "ff+other: emp span emitted");
    assert(html.indexOf('title="Italic"') >= 0,  "ff+other: title shows Italic only (no Font Arial)");
    assertEq(html.indexOf("Font"), -1,           "ff+other: 'Font' not in label");
})();

(function test_diffHasVisibleEmphasis() {
    var fn = EO._internal.diffHasVisibleEmphasis;
    assertEq(fn({ fontStyle: "Bold" }),        true,  "visible: bold");
    assertEq(fn({ underline: true }),          true,  "visible: underline=true");
    assertEq(fn({ underline: false }),         false, "visible: underline=false → not visible");
    assertEq(fn({ fontFamily: "Arial" }),      false, "visible: fontFamily-only → false");
    assertEq(fn({ fontFamily: "Arial",
                  fontStyle: "Bold" }),        true,  "visible: ff + bold → true");
    assertEq(fn({}),                           false, "visible: empty diff → false");
    assertEq(fn(null),                         false, "visible: null → false");
})();

// ─── suggestTargetEmphasisRuns: exact substring tier ──────────────

(function test_suggest_exact_match() {
    var result = EO.suggestTargetEmphasisRuns(
        "Our flagship product, Quantix Pro, is engineered.",
        [{ start: 22, end: 33, diff: { fontStyle: "Bold" } }],   // "Quantix Pro"
        "Our flagship product, Quantix Pro, is the best."
    );
    assertEq(result.runs.length, 1,             "exact: 1 run mapped");
    assertEq(result.runs[0].start, 22,          "exact: target start matches source");
    assertEq(result.runs[0].end,   33,          "exact: target end matches source");
    assertEq(result.runs[0].confidence, "high", "exact: high confidence");
    assertEq(result.stats.exact,        1, "exact: stat count");
})();

(function test_suggest_exact_match_translated_position() {
    // Source prefix changed but emphasized term still appears in target
    var result = EO.suggestTargetEmphasisRuns(
        "Tip: Quantix Pro performs.",                  // emphasized at 5..16
        [{ start: 5, end: 16, diff: { fontStyle: "Bold" } }],
        "提示：Quantix Pro 性能卓越。"                  // "Quantix Pro" at index 3
    );
    assertEq(result.runs.length, 1,        "exact-cjk: 1 run");
    assertEq(result.runs[0].start, 3,      "exact-cjk: located in CJK target");
    assertEq(result.runs[0].end, 14,       "exact-cjk: end at correct offset");
    assertEq(result.runs[0].confidence, "high", "exact-cjk: high confidence");
})();

// ─── suggestTargetEmphasisRuns: word-boundary tier ────────────────

(function test_suggest_word_boundary() {
    var result = EO.suggestTargetEmphasisRuns(
        "He said HELLO loudly.",                                  // emphasized "HELLO" at 8..13
        [{ start: 8, end: 13, diff: { fontStyle: "Bold" } }],
        "She said hello calmly."                                  // "hello" lowercase
    );
    assertEq(result.runs.length, 1,                "word: matched case-insensitive");
    assertEq(result.runs[0].confidence, "medium",  "word: medium confidence");
    assertEq(result.stats.word, 1,                 "word: stat count");
})();

// ─── suggestTargetEmphasisRuns: proportional fallback ─────────────

(function test_suggest_proportional_fallback() {
    var result = EO.suggestTargetEmphasisRuns(
        "abcdefghij",                                              // 10 chars
        [{ start: 2, end: 5, diff: { fontStyle: "Bold" } }],       // "cde" (30-50%)
        "ABCDEFGHIJKLMNOPQRSTUVWXYZ"                                // 26 chars; "cde" not present
    );
    assertEq(result.runs.length, 1, "proportional: still produces a run");
    assertEq(result.runs[0].confidence, "low", "proportional: low confidence");
    // 2*2.6=5.2 → 5; 5*2.6=13 → start≈5, end≈13
    assert(result.runs[0].start >= 4 && result.runs[0].start <= 6, "proportional: start near 30% mark");
    assert(result.runs[0].end   >= 12 && result.runs[0].end   <= 14, "proportional: end near 50% mark");
    assertEq(result.stats.proportional, 1, "proportional: stat count");
})();

// ─── suggestTargetEmphasisRuns: empty / null inputs ───────────────

(function test_suggest_edge_cases() {
    assertEq(EO.suggestTargetEmphasisRuns("foo", null,          "bar").runs.length, 0, "edge: null runs");
    assertEq(EO.suggestTargetEmphasisRuns("foo", [],            "bar").runs.length, 0, "edge: empty runs");
    var dropped = EO.suggestTargetEmphasisRuns("foo",
        [{ start: 0, end: 3, diff: {} }], "");
    assertEq(dropped.runs.length, 0, "edge: empty target → drop");
    assertEq(dropped.stats.dropped, 1, "edge: dropped counter");
})();

// ─── suggestTargetEmphasisRuns: multiple runs preserve diff ───────

(function test_suggest_multiple_diffs_preserved() {
    var src = "Status: Critical alerts in red, warnings in gold.";
    var srcRuns = [
        { start:  8, end: 16, diff: { fontStyle: "Bold", fillColor: { values: [220, 30, 30] } } },
        { start: 32, end: 40, diff: { fontStyle: "Bold", fillColor: { values: [180, 140, 40] } } }
    ];
    // Translated, both keywords present
    var result = EO.suggestTargetEmphasisRuns(src, srcRuns,
        "状态：Critical 警报为红色,warnings 为金色。");
    assertEq(result.runs.length, 2, "multi: 2 runs aligned");
    assertEq(result.runs[0].diff.fontStyle, "Bold", "multi: diff field copied to first run");
    assert(result.runs[0].diff.fillColor && result.runs[0].diff.fillColor.values[0] === 220,
        "multi: fillColor preserved on first");
    assert(result.runs[1].diff.fillColor && result.runs[1].diff.fillColor.values[0] === 180,
        "multi: fillColor preserved on second");
})();

// ─── Summary ──────────────────────────────────────────────────────

if (failures.length === 0) {
    console.log("PASS test_emphasis_overlay (" + passed + " assertions)");
    process.exit(0);
} else {
    console.error("FAIL test_emphasis_overlay — " + failures.length + " of " +
                  (passed + failures.length) + " assertions failed:");
    for (var i = 0; i < failures.length; i++) console.error("  - " + failures[i]);
    process.exit(1);
}

