1	/**
2	 * Source-extracted tests for Phase 4-6 functions.
3	 * Run: node test_phase456.js
4	 */
5	var fs = require("fs");
6	var path = require("path");
7	var vm = require("vm");
8	
9	var appSrc = fs.readFileSync(path.join(__dirname, "app.js"), "utf8");
10	
11	function extractFunction(src, name) {
12	  var idx = src.indexOf("function " + name + "(");
13	  if (idx < 0) throw new Error("Function " + name + " not found in app.js");
14	  var braceStart = src.indexOf("{", idx);
15	  var depth = 0, i = braceStart;
16	  for (; i < src.length; i++) {
17	    if (src[i] === "{") depth++;
18	    else if (src[i] === "}") { depth--; if (depth === 0) break; }
19	  }
20	  return src.substring(idx, i + 1);
21	}
22	
23	var sandbox = {};
24	var fnNames = [
25	  "safeStr", "buildAnnotationContext", "clipAnnotationsToText",
26	  "mergeAdjacentAnnotations", "findAnnotationAtOffset"
27	];
28	var combinedSrc = fnNames.map(function (n) { return extractFunction(appSrc, n); }).join("\n\n");
29	combinedSrc += "\nthis.buildAnnotationContext = buildAnnotationContext;";
30	combinedSrc += "\nthis.clipAnnotationsToText = clipAnnotationsToText;";
31	combinedSrc += "\nthis.mergeAdjacentAnnotations = mergeAdjacentAnnotations;";
32	combinedSrc += "\nthis.findAnnotationAtOffset = findAnnotationAtOffset;";
33	vm.runInNewContext(combinedSrc, sandbox);
34	
35	console.log("OK: extracted Phase 4-6 functions from app.js\n");
36	
37	var passed = 0, failed = 0;
38	function assert(label, actual, expected) {
39	  var a = JSON.stringify(actual), e = JSON.stringify(expected);
40	  if (a === e) { passed++; console.log("  PASS: " + label); }
41	  else { failed++; console.log("  FAIL: " + label); console.log("    expected: " + e); console.log("    actual:   " + a); }
42	}
43	
44	// ── buildAnnotationContext ──
45	console.log("buildAnnotationContext tests:");
46	
47	var bac = sandbox.buildAnnotationContext;
48	
49	assert("basic context",
50	  bac("abcdefghij_HELLO_klmnopqrst", 11, 5),
51	  { context_before: "bcdefghij_", context_after: "_klmnopqrs" });
52	
53	assert("start of text",
54	  bac("HELLO world", 0, 5),
55	  { context_before: "", context_after: " world" });
56	
57	assert("end of text",
58	  bac("hello WORLD", 6, 5),
59	  { context_before: "hello ", context_after: "" });
60	
61	assert("duplicate text expands context", (function () {
62	  var text = "aa_XX_bb_XX_cc";
63	  var ctx = bac(text, 3, 2); // first "XX"
64	  // "XX" appears twice, context should expand to disambiguate
65	  return ctx.context_before.length > 2 || ctx.context_after.length > 2;
66	})(), true);
67	
68	assert("unique text stays at 10",
69	  bac("0123456789UNIQUE0123456789", 10, 6),
70	  { context_before: "0123456789", context_after: "0123456789" });
71	
72	// ── clipAnnotationsToText ──
73	console.log("\nclipAnnotationsToText tests:");
74	
75	var clip = sandbox.clipAnnotationsToText;
76	
77	// Clip with fullText
78	var anns1 = [
79	  { type: "format", action: "bold", text: "abcde", offset: 3, length: 5, context_before: "old", context_after: "old" }
80	];
81	clip(anns1, 6, "abcdef");
82	assert("truncate: length clipped", anns1[0].length, 3);
83	assert("truncate: text synced", anns1[0].text, "def");
84	assert("truncate: context_before updated", typeof anns1[0].context_before, "string");
85	
86	// Remove out-of-bounds
87	var anns2 = [
88	  { type: "format", action: "bold", text: "x", offset: 10, length: 1 }
89	];
90	clip(anns2, 5, "abcde");
91	assert("out-of-bounds removed", anns2.length, 0);
92	
93	// Normal range untouched
94	var anns3 = [
95	  { type: "format", action: "bold", text: "bc", offset: 1, length: 2 }
96	];
97	clip(anns3, 5, "abcde");
98	assert("in-bounds unchanged", anns3.length, 1);
99	assert("in-bounds offset", anns3[0].offset, 1);
100	
101	// Clip to zero length → removed
102	var anns4 = [
103	  { type: "format", action: "bold", text: "x", offset: 5, length: 3 }
104	];
105	clip(anns4, 5, "abcde");
106	assert("offset at boundary removed", anns4.length, 0);
107	
108	// ── mergeAdjacentAnnotations ──
109	console.log("\nmergeAdjacentAnnotations tests:");
110	
111	var merge = sandbox.mergeAdjacentAnnotations;
112	
113	// Adjacent same type → merged
114	var anns5 = [
115	  { type: "format", action: "bold", text: "ab", offset: 0, length: 2 },
116	  { type: "format", action: "bold", text: "cd", offset: 2, length: 2 }
117	];
118	merge(anns5, "abcd");
119	assert("adjacent bold merged: count", anns5.length, 1);
120	assert("adjacent bold merged: range", { offset: anns5[0].offset, length: anns5[0].length }, { offset: 0, length: 4 });
121	assert("adjacent bold merged: text", anns5[0].text, "abcd");
122	
123	// Different action → not merged
124	var anns6 = [
125	  { type: "format", action: "bold", text: "ab", offset: 0, length: 2 },
126	  { type: "format", action: "italic", text: "cd", offset: 2, length: 2 }
127	];
128	merge(anns6, "abcd");
129	assert("different action: not merged", anns6.length, 2);
130	
131	// Overlapping same type → merged
132	var anns7 = [
133	  { type: "format", action: "bold", text: "abc", offset: 0, length: 3 },
134	  { type: "format", action: "bold", text: "cde", offset: 2, length: 3 }
135	];
136	merge(anns7, "abcde");
137	assert("overlapping merged: count", anns7.length, 1);
138	assert("overlapping merged: range", { offset: anns7[0].offset, length: anns7[0].length }, { offset: 0, length: 5 });
139	
140	// Gap between → not merged
141	var anns8 = [
142	  { type: "format", action: "bold", text: "a", offset: 0, length: 1 },
143	  { type: "format", action: "bold", text: "c", offset: 2, length: 1 }
144	];
145	merge(anns8, "abc");
146	assert("gap: not merged", anns8.length, 2);
147	
148	// Color must match
