/**
 * Source-extracted tests for Phase 4-6 functions.
 * Run: node test_phase456.js
 */
var fs = require("fs");
var path = require("path");
var vm = require("vm");

var appSrc = fs.readFileSync(path.join(__dirname, "app.js"), "utf8");

function extractFunction(src, name) {
  var idx = src.indexOf("function " + name + "(");
  if (idx < 0) throw new Error("Function " + name + " not found in app.js");
  var braceStart = src.indexOf("{", idx);
  var depth = 0, i = braceStart;
  for (; i < src.length; i++) {
    if (src[i] === "{") depth++;
    else if (src[i] === "}") { depth--; if (depth === 0) break; }
  }
  return src.substring(idx, i + 1);
}

var sandbox = {};
var fnNames = [
  "safeStr", "buildAnnotationContext", "clipAnnotationsToText",
  "mergeAdjacentAnnotations", "findAnnotationAtOffset"
];
var combinedSrc = fnNames.map(function (n) { return extractFunction(appSrc, n); }).join("\n\n");
combinedSrc += "\nthis.buildAnnotationContext = buildAnnotationContext;";
combinedSrc += "\nthis.clipAnnotationsToText = clipAnnotationsToText;";
combinedSrc += "\nthis.mergeAdjacentAnnotations = mergeAdjacentAnnotations;";
combinedSrc += "\nthis.findAnnotationAtOffset = findAnnotationAtOffset;";
vm.runInNewContext(combinedSrc, sandbox);

console.log("OK: extracted Phase 4-6 functions from app.js\n");

var passed = 0, failed = 0;
function assert(label, actual, expected) {
  var a = JSON.stringify(actual), e = JSON.stringify(expected);
  if (a === e) { passed++; console.log("  PASS: " + label); }
  else { failed++; console.log("  FAIL: " + label); console.log("    expected: " + e); console.log("    actual:   " + a); }
}

// ── buildAnnotationContext ──
console.log("buildAnnotationContext tests:");

var bac = sandbox.buildAnnotationContext;

assert("basic context",
  bac("abcdefghij_HELLO_klmnopqrst", 11, 5),
  { context_before: "bcdefghij_", context_after: "_klmnopqrs" });

assert("start of text",
  bac("HELLO world", 0, 5),
  { context_before: "", context_after: " world" });

assert("end of text",
  bac("hello WORLD", 6, 5),
  { context_before: "hello ", context_after: "" });

assert("duplicate text expands context", (function () {
  var text = "aa_XX_bb_XX_cc";
  var ctx = bac(text, 3, 2); // first "XX"
  // "XX" appears twice, context should expand to disambiguate
  return ctx.context_before.length > 2 || ctx.context_after.length > 2;
})(), true);

assert("unique text stays at 10",
  bac("0123456789UNIQUE0123456789", 10, 6),
  { context_before: "0123456789", context_after: "0123456789" });

// ── clipAnnotationsToText ──
console.log("\nclipAnnotationsToText tests:");

var clip = sandbox.clipAnnotationsToText;

// Clip with fullText
var anns1 = [
  { type: "format", action: "bold", text: "abcde", offset: 3, length: 5, context_before: "old", context_after: "old" }
];
clip(anns1, 6, "abcdef");
assert("truncate: length clipped", anns1[0].length, 3);
assert("truncate: text synced", anns1[0].text, "def");
assert("truncate: context_before updated", typeof anns1[0].context_before, "string");

// Remove out-of-bounds
var anns2 = [
  { type: "format", action: "bold", text: "x", offset: 10, length: 1 }
];
clip(anns2, 5, "abcde");
assert("out-of-bounds removed", anns2.length, 0);

// Normal range untouched
var anns3 = [
  { type: "format", action: "bold", text: "bc", offset: 1, length: 2 }
];
clip(anns3, 5, "abcde");
assert("in-bounds unchanged", anns3.length, 1);
assert("in-bounds offset", anns3[0].offset, 1);

// Clip to zero length → removed
var anns4 = [
  { type: "format", action: "bold", text: "x", offset: 5, length: 3 }
];
clip(anns4, 5, "abcde");
assert("offset at boundary removed", anns4.length, 0);

// ── mergeAdjacentAnnotations ──
console.log("\nmergeAdjacentAnnotations tests:");

var merge = sandbox.mergeAdjacentAnnotations;

// Adjacent same type → merged
var anns5 = [
  { type: "format", action: "bold", text: "ab", offset: 0, length: 2 },
  { type: "format", action: "bold", text: "cd", offset: 2, length: 2 }
];
merge(anns5, "abcd");
assert("adjacent bold merged: count", anns5.length, 1);
assert("adjacent bold merged: range", { offset: anns5[0].offset, length: anns5[0].length }, { offset: 0, length: 4 });
assert("adjacent bold merged: text", anns5[0].text, "abcd");

// Different action → not merged
var anns6 = [
  { type: "format", action: "bold", text: "ab", offset: 0, length: 2 },
  { type: "format", action: "italic", text: "cd", offset: 2, length: 2 }
];
merge(anns6, "abcd");
assert("different action: not merged", anns6.length, 2);

// Overlapping same type → merged
var anns7 = [
  { type: "format", action: "bold", text: "abc", offset: 0, length: 3 },
  { type: "format", action: "bold", text: "cde", offset: 2, length: 3 }
];
merge(anns7, "abcde");
assert("overlapping merged: count", anns7.length, 1);
assert("overlapping merged: range", { offset: anns7[0].offset, length: anns7[0].length }, { offset: 0, length: 5 });

// Gap between → not merged
var anns8 = [
  { type: "format", action: "bold", text: "a", offset: 0, length: 1 },
  { type: "format", action: "bold", text: "c", offset: 2, length: 1 }
];
merge(anns8, "abc");
assert("gap: not merged", anns8.length, 2);

// Color must match
var anns9 = [
  { type: "format", action: "color", text: "ab", offset: 0, length: 2, color: "#ff0000" },
  { type: "format", action: "color", text: "cd", offset: 2, length: 2, color: "#00ff00" }
];
merge(anns9, "abcd");
assert("different color: not merged", anns9.length, 2);

// ── findAnnotationAtOffset ──
console.log("\nfindAnnotationAtOffset tests:");

var find = sandbox.findAnnotationAtOffset;

var annsF = [
  { type: "format", action: "bold", offset: 0, length: 6 },   // wider
  { type: "format", action: "italic", offset: 1, length: 3 }  // narrower
];
assert("returns narrowest", find(annsF, 2), 1);
assert("outside all", find(annsF, 10), -1);
assert("at boundary (exclusive end)", find(annsF, 6), -1);

// ── removeAnnotationFromRange (source-extracted with DOM stubs) ──
console.log("\nremoveAnnotationFromRange tests:");

// Extract the real function and run it with stubbed DOM dependencies
var removeSandbox = {};
var removeSrc = extractFunction(appSrc, "safeStr") + "\n" +
  extractFunction(appSrc, "buildAnnotationContext") + "\n" +
  extractFunction(appSrc, "removeAnnotationFromRange") + "\n" +
  // Stub DOM-dependent functions that removeAnnotationFromRange calls
  "function resolveTextareaTid(a) { return a.__tid || ''; }\n" +
  "function syncAnnotationVisuals() {}\n" +
  "function refreshAnnToolbar() {}\n" +
  "var state = { translationsByTid: {} };\n" +
  "this.removeAnnotationFromRange = removeAnnotationFromRange;\n" +
  "this.state = state;\n";
vm.runInNewContext(removeSrc, removeSandbox);

// Wrapper: set up stubbed state, call real function, return result
function testRemoveFromRange(annotations, annIdx, selStart, selEnd, fullText) {
  var anns = JSON.parse(JSON.stringify(annotations));
  var tid = "test_tid";
  removeSandbox.state.translationsByTid[tid] = { annotations: anns };
  var fakeArea = { __tid: tid, value: fullText };
  removeSandbox.removeAnnotationFromRange(fakeArea, annIdx, selStart, selEnd);
  return removeSandbox.state.translationsByTid[tid].annotations;
}

// Full cover → delete
var rr1 = testRemoveFromRange(
  [{ type: "format", action: "bold", text: "abc", offset: 0, length: 3 }],
  0, 0, 3, "abc"
);
assert("full cover → delete", rr1.length, 0);

// Sub-range middle → split into left + right
var rr2 = testRemoveFromRange(
  [{ type: "format", action: "bold", text: "abcde", offset: 0, length: 5 }],
  0, 2, 4, "abcde"
);
assert("middle split: count", rr2.length, 2);
assert("middle split: left", { offset: rr2[0].offset, length: rr2[0].length, text: rr2[0].text }, { offset: 0, length: 2, text: "ab" });
assert("middle split: right", { offset: rr2[1].offset, length: rr2[1].length, text: rr2[1].text }, { offset: 4, length: 1, text: "e" });

// Sub-range left edge → only right part survives
var rr3 = testRemoveFromRange(
  [{ type: "format", action: "bold", text: "abcde", offset: 0, length: 5 }],
  0, 0, 3, "abcde"
);
assert("left edge: count", rr3.length, 1);
assert("left edge: right part", { offset: rr3[0].offset, length: rr3[0].length, text: rr3[0].text }, { offset: 3, length: 2, text: "de" });

// Sub-range right edge → only left part survives
var rr4 = testRemoveFromRange(
  [{ type: "format", action: "bold", text: "abcde", offset: 0, length: 5 }],
  0, 3, 5, "abcde"
);
assert("right edge: count", rr4.length, 1);
assert("right edge: left part", { offset: rr4[0].offset, length: rr4[0].length, text: rr4[0].text }, { offset: 0, length: 3, text: "abc" });

// Other annotations untouched
var rr5 = testRemoveFromRange(
  [
    { type: "format", action: "bold", text: "abc", offset: 0, length: 3 },
    { type: "format", action: "italic", text: "de", offset: 3, length: 2 }
  ],
  0, 1, 2, "abcde"
);
assert("other untouched: count", rr5.length, 3); // left + right of bold + italic
assert("other untouched: italic preserved", { offset: rr5[0].offset, action: rr5[0].action }, { offset: 3, action: "italic" });

// ── chunkAnnSig continuity (via buildOverlayHtml output) ──
console.log("\nchunkAnnSig continuity tests:");

// Need buildOverlayHtml from app.js
var sandbox2 = {};
var fnNames2 = ["safeStr", "escapeHtmlText", "escapeHtmlAttr", "tokenAwareHtml", "buildOverlayHtml"];
var src2 = fnNames2.map(function (n) { return extractFunction(appSrc, n); }).join("\n\n");
src2 += "\nthis.buildOverlayHtml = buildOverlayHtml;";
vm.runInNewContext(src2, sandbox2);
var buildOH = sandbox2.buildOverlayHtml;

// Adjacent same format → cont classes present (no gap)
var html1 = buildOH("abcd", [
  { type: "format", action: "bold", text: "ab", offset: 0, length: 2 },
  { type: "format", action: "bold", text: "cd", offset: 2, length: 2 }
]);
assert("same format adjacent: has ann-cont-right", html1.indexOf("ann-cont-right") >= 0, true);
assert("same format adjacent: has ann-cont-left", html1.indexOf("ann-cont-left") >= 0, true);

// Adjacent different format → no cont classes (gap)
var html2 = buildOH("abcd", [
  { type: "format", action: "bold", text: "ab", offset: 0, length: 2 },
  { type: "format", action: "italic", text: "cd", offset: 2, length: 2 }
]);
assert("diff format adjacent: no ann-cont-right", html2.indexOf("ann-cont-right") < 0, true);
assert("diff format adjacent: no ann-cont-left", html2.indexOf("ann-cont-left") < 0, true);

// One italic, adjacent italic+bold → different annotation sets → no cont
var html3 = buildOH("abcdef", [
  { type: "format", action: "italic", text: "abc", offset: 0, length: 3 },
  { type: "format", action: "italic", text: "def", offset: 3, length: 3 },
  { type: "format", action: "bold", text: "def", offset: 3, length: 3 }
]);
// At boundary 3: left chunk has {italic}, right chunk has {italic, bold} → different sets → gap
assert("italic vs italic+bold: no cont (different sets)", html3.indexOf("ann-cont-right") < 0, true);

// Same two formats on both sides → cont
var html4 = buildOH("abcd", [
  { type: "format", action: "bold", text: "abcd", offset: 0, length: 4 },
  { type: "format", action: "italic", text: "ab", offset: 0, length: 2 },
  { type: "format", action: "italic", text: "cd", offset: 2, length: 2 }
]);
// Both chunks have {bold, italic} → same set → continuous
assert("bold+italic both sides: has cont", html4.indexOf("ann-cont-right") >= 0, true);

console.log("\n" + passed + " passed, " + failed + " failed");
process.exit(failed > 0 ? 1 : 0);

